1419→    protected open fun playSounds(doAudioReplay: Boolean) {
1420→        // this can occur due to OpChanges when the viewer is on another screen
1421→        if (!this.lifecycle.currentState.isAtLeast(RESUMED)) {
1422→            Timber.w("sounds are not played as the activity is inactive")
1423→            return
1424→        }
1425→        if (!soundPlayer.config.autoplay && !doAudioReplay) return
1426→        // Use TTS if TTS preference enabled and no other sound source
1427→        val useTTS = tts.enabled && !soundPlayer.hasSounds(displayAnswer)
1428→        // We need to play the sounds from the proper side of the card
1429→        if (!useTTS) {
1430→            launchCatchingTask {
1431→                val side = if (displayAnswer) SingleCardSide.BACK else SingleCardSide.FRONT
1432→                when (doAudioReplay) {
1433→                    true -> soundPlayer.replayAllSounds(side)
1434→                    false -> soundPlayer.playAllSounds(side)
1435→                }
1436→            }
1437→            return
1438→        }
1439→
1440→        val replayQuestion = soundPlayer.config.replayQuestion
1441→        // Text to speech is in effect here
1442→        // If the question is displayed or if the question should be replayed, read the question
1443→        if (ttsInitialized) {
1444→            if (!displayAnswer || doAudioReplay && replayQuestion) {
1445→                readCardTts(SingleCardSide.FRONT)
1446→            }
1447→            if (displayAnswer) {
1448→                readCardTts(SingleCardSide.BACK)
1449→            }
1450→        } else {
1451→            replayOnTtsInit = true
1452→        }
1453→    }
