","new_string":"fun parseSourcesToFileScheme(content: String, mediaDir: String): String {
    val doc = Jsoup.parseBodyFragment(content)
    doc.outputSettings(OutputSettings().prettyPrint(false))

    fun replaceWithFileScheme(
        tag: String,
        attr: String,
        shouldReplace: (Element, String) -> Boolean = { _, _ -> true }
    ): Boolean {
        var madeChanges = false
        for (elem in doc.select(tag)) {
            val attrValue = elem.attr(attr)
            if (attrValue.isEmpty()) continue
            if (!shouldReplace(elem, attrValue)) continue

            val attrUri = try {
                URI(attrValue)
            } catch (_: URISyntaxException) {
                continue
            }
            if (attrUri.scheme != null) continue

            val path = Paths.get(mediaDir, attrUri.path).toString()
            val newUri = getFileUri(path)

            elem.attr(attr, newUri.toString())
            madeChanges = true
        }
        return madeChanges
    }

    fun shouldConvertObject(attrValue: String, element: Element): Boolean {
        val mimeType = element.attr("type")
        if (mimeType.isNotEmpty() && mimeType.lowercase(Locale.ROOT).contains("svg")) {
            return false
        }
        val withoutFragment = attrValue.substringBefore('#')
        val sanitizedPath = withoutFragment.substringBefore('?')
        if (sanitizedPath.lowercase(Locale.ROOT).endsWith(".svg")) {
            return false
        }
        return true
    }

    val hasMadeChanges =
        replaceWithFileScheme("img", "src") ||
            replaceWithFileScheme("video", "src") ||
            replaceWithFileScheme("audio", "src") ||
            replaceWithFileScheme("source", "src") ||
            replaceWithFileScheme("object", "data") { element, attrValue ->
                shouldConvertObject(attrValue, element)
            }

    return if (hasMadeChanges) {
        doc.body().html()
    } else {
        content
    }
}
